// Cloudflare Worker with SendGrid and Stripe Integration

const ALLOWED_ORIGINS = ['https://yourdomain.com', 'https://www.yourdomain.com'];

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, Authorization',
  'Access-Control-Max-Age': '86400',
};

class APIError extends Error {
  constructor(message, status = 500, code = 'INTERNAL_ERROR') {
    super(message);
    this.status = status;
    this.code = code;
  }
}

class SendGridService {
  constructor(apiKey) {
    this.apiKey = apiKey;
    this.baseUrl = 'https://api.sendgrid.com/v3';
  }

  async sendEmail({ to, from, subject, text, html }) {
    if (!to || !from || !subject || (!text && !html)) {
      throw new APIError('Missing required email parameters', 400, 'INVALID_EMAIL_PARAMS');
    }

    const payload = {
      personalizations: [{ to: [{ email: to }] }],
      from: { email: from },
      subject: subject,
    };

    if (html) {
      payload.content = [{ type: 'text/html', value: html }];
    } else {
      payload.content = [{ type: 'text/plain', value: text }];
    }

    try {
      const response = await fetch(`${this.baseUrl}/mail/send`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${this.apiKey}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload),
      });

      if (!response.ok) {
        const errorText = await response.text();
        let errorData;
        try {
          errorData = JSON.parse(errorText);
        } catch {
          errorData = { message: errorText };
        }
        throw new APIError(
          errorData.errors?.[0]?.message || errorData.message || 'SendGrid API error',
          response.status,
          'SENDGRID_ERROR'
        );
      }

      return { success: true, messageId: response.headers.get('X-Message-Id') };
    } catch (error) {
      if (error instanceof APIError) throw error;
      throw new APIError(`SendGrid request failed: ${error.message}`, 500, 'SENDGRID_REQUEST_FAILED');
    }
  }

  async validateEmail(email) {
    try {
      const response = await fetch(`${this.baseUrl}/validations/email`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${this.apiKey}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ email }),
      });

      if (!response.ok) {
        throw new APIError('Email validation failed', response.status, 'VALIDATION_ERROR');
      }

      return await response.json();
    } catch (error) {
      if (error instanceof APIError) throw error;
      throw new APIError(`Email validation request failed: ${error.message}`, 500, 'VALIDATION_REQUEST_FAILED');
    }
  }
}

class StripeService {
  constructor(apiKey) {
    this.apiKey = apiKey;
    this.baseUrl = 'https://api.stripe.com/v1';
  }

  async createPaymentIntent({ amount, currency = 'usd', metadata = {} }) {
    if (!amount || amount <= 0) {
      throw new APIError('Invalid amount', 400, 'INVALID_AMOUNT');
    }

    const params = new URLSearchParams({
      amount: Math.round(amount),
      currency: currency.toLowerCase(),
    });

    Object.entries(metadata).forEach(([key, value]) => {
      params.append(`metadata[${key}]`, value);
    });

    try {
      const response = await fetch(`${this.baseUrl}/payment_intents`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${this.apiKey}`,
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: params.toString(),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new APIError(
          data.error?.message || 'Stripe API error',
          response.status,
          data.error?.code || 'STRIPE_ERROR'
        );
      }

      return {
        id: data.id,
        clientSecret: data.client_secret,
        amount: data.amount,
        currency: data.currency,
        status: data.status,
      };
    } catch (error) {
      if (error instanceof APIError) throw error;
      throw new APIError(`Stripe request failed: ${error.message}`, 500, 'STRIPE_REQUEST_FAILED');
    }
  }

  async retrievePaymentIntent(paymentIntentId) {
    if (!paymentIntentId) {
      throw new APIError('Payment Intent ID required', 400, 'MISSING_PAYMENT_INTENT_ID');
    }

    try {
      const response = await fetch(`${this.baseUrl}/payment_intents/${paymentIntentId}`, {
        method: 'GET',
        headers: {
          'Authorization': `Bearer ${this.apiKey}`,
        },
      });

      const data = await response.json();

      if (!response.ok) {
        throw new APIError(
          data.error?.message || 'Failed to retrieve payment intent',
          response.status,
          data.error?.code || 'STRIPE_RETRIEVE_ERROR'
        );
      }

      return {
        id: data.id,
        amount: data.amount,
        currency: data.currency,
        status: data.status,
        metadata: data.metadata,
      };
    } catch (error) {
      if (error instanceof APIError) throw error;
      throw new APIError(`Failed to retrieve payment intent: ${error.message}`, 500, 'STRIPE_RETRIEVE_FAILED');
    }
  }

  async createCustomer({ email, name, metadata = {} }) {
    if (!email) {
      throw new APIError('Email required for customer creation', 400, 'MISSING_EMAIL');
    }

    const params = new URLSearchParams({ email });
    if (name) params.append('name', name);
    
    Object.entries(metadata).forEach(([key, value]) => {
      params.append(`metadata[${key}]`, value);
    });

    try {
      const response = await fetch(`${this.baseUrl}/customers`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${this.apiKey}`,
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: params.toString(),
      });

      const data = await response.json();

      if (!response.ok) {
        throw new APIError(
          data.error?.message || 'Failed to create customer',
          response.status,
          data.error?.code || 'CUSTOMER_CREATE_ERROR'
        );
      }

      return {
        id: data.id,
        email: data.email,
        name: data.name,
        created: data.created,
      };
    } catch (error) {
      if (error instanceof APIError) throw error;
      throw new APIError(`Customer creation failed: ${error.message}`, 500, 'CUSTOMER_CREATE_FAILED');
    }
  }

  async verifyWebhook(payload, signature, secret) {
    const encoder = new TextEncoder();
    const data = encoder.encode(payload);
    const key = await crypto.subtle.importKey(
      'raw',
      encoder.encode(secret),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['verify']
    );

    const signatureParts = signature.split(',');
    const timestamp = signatureParts.find(part => part.startsWith('t=')).split('=')[1];
    const signatures = signatureParts.filter(part => part.startsWith('v1=')).map(part => part.split('=')[1]);

    const signedPayload = `${timestamp}.${payload}`;
    const expectedSignature = await crypto.subtle.sign(
      'HMAC',
      key,
      encoder.encode(signedPayload)
    );

    const expectedSigHex = Array.from(new Uint8Array(expectedSignature))
      .map(b => b.toString(16).padStart(2, '0'))
      .join('');

    return signatures.some(sig => sig === expectedSigHex);
  }
}

function validateApiKey(request, env) {
  const authHeader = request.headers.get('Authorization');
  
  if (!authHeader) {
    throw new APIError('Missing Authorization header', 401, 'MISSING_AUTH');
  }

  const [scheme, token] = authHeader.split(' ');

  if (scheme !== 'Bearer' || !token) {
    throw new APIError('Invalid Authorization format', 401, 'INVALID_AUTH_FORMAT');
  }

  if (token !== env.API_KEY) {
    throw new APIError('Invalid API key', 403, 'INVALID_API_KEY');
  }

  return true;
}

function validateOrigin(request) {
  const origin = request.headers.get('Origin');
  
  if (origin && !ALLOWED_ORIGINS.includes(origin)) {
    throw new APIError('Origin not allowed', 403, 'FORBIDDEN_ORIGIN');
  }
  
  return origin;
}

async function handleSendEmail(request, env) {
  const body = await request.json();
  const sendGrid = new SendGridService(env.SENDGRID_API_KEY);
  
  const result = await sendGrid.sendEmail({
    to: body.to,
    from: body.from || env.DEFAULT_FROM_EMAIL,
    subject: body.subject,
    text: body.text,
    html: body.html,
  });

  return new Response(JSON.stringify(result), {
    status: 200,
    headers: { 'Content-Type': 'application/json', ...corsHeaders },
  });
}

async function handleValidateEmail(request, env) {
  const body = await request.json();
  const sendGrid = new SendGridService(env.SENDGRID_API_KEY);
  
  const result = await sendGrid.validateEmail(body.email);

  return new Response(JSON.stringify(result), {
    status: 200,
    headers: { 'Content-Type': 'application/json', ...corsHeaders },
  });
}

async function handleCreatePayment(request, env) {
  const body = await request.json();
  const stripe = new StripeService(env.STRIPE_SECRET_KEY);
  
  const result = await stripe.createPaymentIntent({
    amount: body.amount,
    currency: body.currency,
    metadata: body.metadata,
  });

  return new Response(JSON.stringify(result), {
    status: 200,
    headers: { 'Content-Type': 'application/json', ...corsHeaders },
  });
}

async function handleGetPayment(request, env) {
  const url = new URL(request.url);
  const paymentIntentId = url.searchParams.get('id');
  
  const stripe = new StripeService(env.STRIPE_SECRET_KEY);
  const result = await stripe.retrievePaymentIntent(paymentIntentId);

  return new Response(JSON.stringify(result), {
    status: 200,
    headers: { 'Content-Type': 'application/json', ...corsHeaders },
  });
}

async function handleCreateCustomer(request, env) {
  const body = await request.json();
  const stripe = new StripeService(env.STRIPE_SECRET_KEY);
  
  const result = await stripe.createCustomer({
    email: body.email,
    name: body.name,
    metadata: body.metadata,
  });

  return new Response(JSON.stringify(result), {
    status: 200,
    headers: { 'Content-Type': 'application/json', ...corsHeaders },
  });
}

async function handleStripeWebhook(request, env) {
  const signature = request.headers.get('stripe-signature');
  const payload = await request.text();
  
  const stripe = new StripeService(env.STRIPE_SECRET_KEY);
  const isValid = await stripe.verifyWebhook(payload, signature, env.STRIPE_WEBHOOK_SECRET);
  
  if (!isValid) {
    throw new APIError('Invalid webhook signature', 400, 'INVALID_SIGNATURE');
  }

  const event = JSON.parse(payload);

  switch (event.type) {
    case 'payment_intent.succeeded':
      console.log('Payment succeeded:', event.data.object.id);
      break;
    case 'payment_intent.payment_failed':
      console.log('Payment failed:', event.data.object.id);
      break;
    default:
      console.log('Unhandled event type:', event.type);
  }

  return new Response(JSON.stringify({ received: true }), {
    status: 200,
    headers: { 'Content-Type': 'application/json' },
  });
}

async function handleRequest(request, env) {
  const url = new URL(request.url);
  const path = url.pathname;

  if (request.method === 'OPTIONS') {
    return new Response(null, {
      status: 204,
      headers: corsHeaders,
    });
  }

  if (path === '/webhook/stripe') {
    return await handleStripeWebhook(request, env);
  }

  validateApiKey(request, env);

  const routes = {
    '/email/send': { method: 'POST', handler: handleSendEmail },
    '/email/validate': { method: 'POST', handler: handleValidateEmail },
    '/payment/create': { method: 'POST', handler: handleCreatePayment },
    '/payment/get': { method: 'GET', handler: handleGetPayment },
    '/customer/create': { method: 'POST', handler: handleCreateCustomer },
  };

  const route = routes[path];

  if (!route) {
    throw new APIError('Route not found', 404, 'NOT_FOUND');
  }

  if (request.method !== route.method) {
    throw new APIError('Method not allowed', 405, 'METHOD_NOT_ALLOWED');
  }

  return await route.handler(request, env);
}

async function handleError(error) {
  console.error('Error:', error);

  const status = error.status || 500;
  const code = error.code || 'INTERNAL_ERROR';
  const message = error.message || 'Internal server error';

  return new Response(
    JSON.stringify({
      error: {
        code,
        message,
        status,
      },
    }),
    {
      status,
      headers: { 'Content-Type': 'application/json', ...corsHeaders },
    }
  );
}

export default {
  async fetch(request, env, ctx) {
    try {
      return await handleRequest(request, env);
    } catch (error) {
      return await handleError(error);
    }
  },
};